const prometheusText = $input.first().json.data || $input.first().json;

// Prometheus 메트릭 파싱 함수
function parsePrometheusMetric(text, metricName) {
  const regex = new RegExp(`^${metricName}(?:\\{[^}]*\\})?\\s+([0-9.]+)`, 'gm');
  const matches = [...String(text).matchAll(regex)];
  if (matches.length === 0) return null;
  return parseFloat(matches[matches.length - 1][1]);
}

// 메트릭 추출
const rateLimitedTotal = parsePrometheusMetric(prometheusText, 'useragent_rate_limited_total') || 0;
const circuitBreakerTotal = parsePrometheusMetric(prometheusText, 'useragent_circuit_breaker_total') || 0;
const suspendedTotal = parsePrometheusMetric(prometheusText, 'useragent_suspended_total') || 0;
const poolAvailable = parsePrometheusMetric(prometheusText, 'useragent_pool_available') || 0;
const poolTotal = parsePrometheusMetric(prometheusText, 'useragent_pool_total') || 1;
const poolAvailableRate = parsePrometheusMetric(prometheusText, 'useragent_pool_available_rate') || 0;

// 이전 실행 값과 비교를 위한 정적 데이터 (n8n의 staticData 활용)
const staticData = $getWorkflowStaticData('global');
const prevRateLimited = staticData.prevRateLimited || 0;
const prevCircuitBreaker = staticData.prevCircuitBreaker || 0;
const lastCheckTime = staticData.lastCheckTime || Date.now();

// 증가량 계산 (3분 내)
const rateLimitedIncrease = rateLimitedTotal - prevRateLimited;
const circuitBreakerIncrease = circuitBreakerTotal - prevCircuitBreaker;
const timeDiffMinutes = (Date.now() - lastCheckTime) / (1000 * 60);

// 분당 Rate Limit 발생률
const rateLimitedPerMinute = timeDiffMinutes > 0 
  ? (rateLimitedIncrease / timeDiffMinutes).toFixed(2) 
  : 0;

// 현재 값 저장 (다음 실행을 위해)
staticData.prevRateLimited = rateLimitedTotal;
staticData.prevCircuitBreaker = circuitBreakerTotal;
staticData.lastCheckTime = Date.now();

// 알림 조건 체크
const alerts = [];

// 3분 내 10회 이상 Rate Limit
if (rateLimitedIncrease >= 10) {
  alerts.push({
    type: 'CRITICAL',
    metric: 'rate_limited_spike',
    value: rateLimitedIncrease,
    message: `🚨 Rate Limit 급증! 3분 내 ${rateLimitedIncrease}회 (분당 ${rateLimitedPerMinute}회)`
  });
} else if (rateLimitedIncrease >= 5) {
  alerts.push({
    type: 'WARNING',
    metric: 'rate_limited_increase',
    value: rateLimitedIncrease,
    message: `⚠️ Rate Limit 증가: 3분 내 ${rateLimitedIncrease}회`
  });
}

// Circuit Breaker 급증
if (circuitBreakerIncrease >= 3) {
  alerts.push({
    type: 'CRITICAL',
    metric: 'circuit_breaker_spike',
    value: circuitBreakerIncrease,
    message: `🚨 Circuit Breaker ${circuitBreakerIncrease}회 발동! UserAgent 차단 위험`
  });
}

// Pool 고갈 위험
if (poolAvailableRate < 30) {
  alerts.push({
    type: 'CRITICAL',
    metric: 'pool_exhaustion',
    value: poolAvailableRate,
    message: `🚨 UserAgent Pool 고갈 위험! ${poolAvailable}/${poolTotal} (${poolAvailableRate.toFixed(1)}%)`
  });
} else if (poolAvailableRate < 50) {
  alerts.push({
    type: 'WARNING',
    metric: 'pool_low',
    value: poolAvailableRate,
    message: `⚠️ UserAgent Pool 부족: ${poolAvailable}/${poolTotal} (${poolAvailableRate.toFixed(1)}%)`
  });
}

// 자동 복구 조건: CRITICAL 알림 중 Rate Limit 또는 Pool 관련
const shouldAutoRecover = alerts.some(a => 
  a.type === 'CRITICAL' && 
  (a.metric === 'rate_limited_spike' || a.metric === 'pool_exhaustion' || a.metric === 'circuit_breaker_spike')
);

return {
  timestamp: new Date().toISOString(),
  metrics: {
    rateLimited: {
      total: rateLimitedTotal,
      increase: rateLimitedIncrease,
      perMinute: parseFloat(rateLimitedPerMinute)
    },
    circuitBreaker: {
      total: circuitBreakerTotal,
      increase: circuitBreakerIncrease
    },
    suspended: suspendedTotal,
    pool: {
      available: poolAvailable,
      total: poolTotal,
      availableRate: poolAvailableRate
    }
  },
  alerts,
  hasAlerts: alerts.length > 0,
  hasCritical: alerts.some(a => a.type === 'CRITICAL'),
  shouldAutoRecover
};

const data = $input.first().json;
const alerts = data.alerts;
const metrics = data.metrics;

const hasCritical = data.hasCritical;
const emoji = hasCritical ? '🚨' : '⚠️';
const color = hasCritical ? '#ff0000' : '#ffcc00';
const alertText = alerts.map(a => a.message).join('\n');

const slackMessage = {
  text: `${emoji} CrawlingHub Rate Limit Alert`,
  attachments: [
    {
      color: color,
      blocks: [
        {
          type: 'header',
          text: {
            type: 'plain_text',
            text: `${emoji} CrawlingHub Rate Limit 알림`,
            emoji: true
          }
        },
        {
          type: 'section',
          text: {
            type: 'mrkdwn',
            text: alertText
          }
        },
        {
          type: 'divider'
        },
        {
          type: 'section',
          fields: [
            {
              type: 'mrkdwn',
              text: `*Rate Limited (429)*\n총 ${metrics.rateLimited.total}회 (+${metrics.rateLimited.increase})`
            },
            {
              type: 'mrkdwn',
              text: `*분당 발생률*\n${metrics.rateLimited.perMinute}회/분`
            },
            {
              type: 'mrkdwn',
              text: `*Circuit Breaker*\n총 ${metrics.circuitBreaker.total}회 (+${metrics.circuitBreaker.increase})`
            },
            {
              type: 'mrkdwn',
              text: `*Suspended*\n${metrics.suspended}개`
            },
            {
              type: 'mrkdwn',
              text: `*Pool 상태*\n${metrics.pool.available}/${metrics.pool.total} (${metrics.pool.availableRate.toFixed(1)}%)`
            },
            {
              type: 'mrkdwn',
              text: `*자동 복구*\n${data.shouldAutoRecover ? '✅ 실행 예정' : '❌ 불필요'}`
            }
          ]
        },
        {
          type: 'context',
          elements: [
            {
              type: 'mrkdwn',
              text: `⏰ ${data.timestamp}`
            }
          ]
        }
      ]
    }
  ]
};

return { slackMessage, shouldAutoRecover: data.shouldAutoRecover, hasCritical };

